721→  surreal: Surreal;
722→  sessionId: string;
723→  text: string;
724→};
725→
726→export async function sendSessionPrompt(
727→  input: SendPromptInput,
728→): Promise<PromptSessionResult> {
729→  const lookup = await lookupSession(input.surreal, input.sessionId);
730→  if (!lookup.ok) {
731→    return { ok: false, error: lookup.error };
732→  }
733→  const { status } = lookup;
734→
735→  if (!PROMPTABLE_STATUSES.has(status)) {
736→    return { ok: false, error: sessionStateConflict(input.sessionId, status, "prompt") };
737→  }
738→
739→  // The Claude Agent SDK uses a single query() call per conversation.
740→  // Follow-up prompts are not supported in this model.
741→  return {
742→    ok: false,
743→    error: {
744→      code: "SESSION_ERROR",
745→      message: `Follow-up prompts are not supported with the Agent SDK. Session ${input.sessionId} runs a single query() conversation.`,
746→      httpStatus: 409,
747→    },
748→  };
749→}
