 16→export async function processGitCommits(input: ProcessWebhookInput): Promise<ProcessWebhookResult> {
 17→  const startedAt = performance.now();
 18→  const workspaceId = input.workspaceRecord.id as string;
 19→
 20→  logInfo("webhook.commits.started", "Processing commits", {
 21→    workspaceId,
 22→    repository: input.event.repository.full_name,
 23→    commitCount: input.event.commits.length,
 24→  });
 25→
 26→  const projects = await loadWorkspaceProjects(input.surreal, input.workspaceRecord);
 27→  const projectNames = projects.map((p) => p.name);
 28→
 29→  const [workspaceRows] = await input.surreal
 30→    .query<[Array<{ name: string }>]>("SELECT name FROM $workspace LIMIT 1;", {
 31→      workspace: input.workspaceRecord,
 32→    })
 33→    .collect<[Array<{ name: string }>]>();
 34→  const workspaceName = workspaceRows[0]?.name;
 35→
 36→  const result: ProcessWebhookResult = {
 37→    commitsProcessed: 0,
 38→    commitsSkipped: 0,
 39→    totalEntities: 0,
 40→    totalRelationships: 0,
 41→    autoLinkedDecisions: [],
 42→    observationsCreated: [],
 43→  };
 44→
 45→  for (const rawCommit of input.event.commits) {
 46→    const commit: CommitInput = {
 47→      sha: rawCommit.id,
 48→      message: rawCommit.message,
 49→      authoredAt: rawCommit.timestamp,
 50→      authorName: rawCommit.author.name,
 51→      authorEmail: rawCommit.author.email,
 52→      authorUsername: rawCommit.author.username,
 53→      url: rawCommit.url,
 54→      repository: input.event.repository.full_name,
 55→    };
 56→
 57→    try {
 58→      const commitResult = await processCommit({
 59→        surreal: input.surreal,
 60→        extractionModel: input.extractionModel,
 61→        embeddingModel: input.embeddingModel,
 62→        embeddingDimension: input.embeddingDimension,
 63→        extractionStoreThreshold: input.extractionStoreThreshold,
 64→        extractionModelId: input.extractionModelId,
 65→        workspaceRecord: input.workspaceRecord,
 66→        commit,
 67→        workspaceName,
 68→        projectNames,
 69→        autoLinkThreshold: input.autoLinkThreshold,
 70→        now: new Date(),
 71→      });
 72→
 73→      result.commitsProcessed += 1;
 74→      result.totalEntities += commitResult.entities.length;
 75→      result.totalRelationships += commitResult.relationships.length;
 76→      result.autoLinkedDecisions.push(...commitResult.autoLinkedDecisions);
 77→      result.observationsCreated.push(...commitResult.observationsCreated);
 78→    } catch (error) {
 79→      logError("webhook.commit.failed", "Failed to process commit", error, {
 80→        workspaceId,
 81→        sha: commit.sha,
 82→      });
 83→      result.commitsSkipped += 1;
 84→    }
 85→  }
 86→
 87→  logInfo("webhook.commits.completed", "Finished processing commits", {
 88→    workspaceId,
 89→    ...result,
 90→    durationMs: elapsedMs(startedAt),
 91→  });
 92→
 93→  return result;
 94→}
 95→
 96→async function processCommit(input: {
 97→  surreal: typeof import("surrealdb").Surreal.prototype;
 98→  extractionModel: unknown;
 99→  embeddingModel: unknown;
100→  embeddingDimension: number;
101→  extractionStoreThreshold: number;
102→  extractionModelId: string;
103→  workspaceRecord: RecordId<"workspace", string>;
104→  commit: CommitInput;
105→  workspaceName?: string;
106→  projectNames?: string[];
107→  autoLinkThreshold: number;
108→  now: Date;
109→}): Promise<ProcessCommitResult> {
110→  const commitRecordId = randomUUID();
111→  const commitRecord = new RecordId("git_commit", commitRecordId);
112→
113→  // Resolve author
114→  const authorRecord = await findWorkspacePersonByName({
115→    surreal: input.surreal,
116→    workspaceRecord: input.workspaceRecord,
117→    personName: input.commit.authorName,
118→  });
119→
120→  // Create embedding for commit message
121→  const embedding = await createEmbedding(
122→    input.embeddingModel,
123→    input.embeddingDimension,
124→    input.commit.message,
125→  );
126→
127→  // Persist git_commit record
128→  await input.surreal.create(commitRecord).content({
129→    sha: input.commit.sha,
130→    repository: input.commit.repository,
131→    message: input.commit.message,
132→    authored_at: new Date(input.commit.authoredAt),
133→    ...(authorRecord ? { author: authorRecord } : {}),
134→    author_name: input.commit.authorName,
135→    url: input.commit.url,
136→    workspace: input.workspaceRecord,
137→    ...(embedding ? { embedding } : {}),
138→    created_at: input.now,
139→  });
140→
141→  logInfo("webhook.commit.created", "Created git_commit record", {
142→    sha: input.commit.sha,
143→    commitRecordId,
144→  });
145→
146→  const referencedTaskIds = extractReferencedTaskIds(input.commit.message);
147→  let linkedTaskCount = 0;
148→  let unresolvedTaskIds: string[] = [];
149→  let linkedTaskSummaries: Array<{ id: string; title: string }> = [];
150→
151→  if (referencedTaskIds.length > 0) {
152→    const taskRecords = referencedTaskIds.map((taskId) => new RecordId("task", taskId));
153→    const [taskRows] = await input.surreal
154→      .query<[Array<{ id: RecordId<"task", string>; title: string }> ]>(
155→        "SELECT id, title FROM task WHERE workspace = $workspace AND id IN $taskIds;",
156→        { workspace: input.workspaceRecord, taskIds: taskRecords },
157→      )
158→      .collect<[Array<{ id: RecordId<"task", string>; title: string }>]>();
159→
160→    const foundTaskIds = new Set(taskRows.map((row) => row.id.id as string));
161→    unresolvedTaskIds = referencedTaskIds.filter((id) => !foundTaskIds.has(id));
162→
163→    for (const task of taskRows) {
164→      await input.surreal
165→        .relate(task.id, new RecordId("implemented_by", randomUUID()), commitRecord, {
166→          commit_sha: input.commit.sha,
167→          linked_at: input.now,
168→        })
169→        .output("after");
170→    }
171→
172→    linkedTaskCount = taskRows.length;
173→    linkedTaskSummaries = taskRows.map((row) => ({
174→      id: row.id.id as string,
175→      title: row.title,
176→    }));
177→  }
178→
179→  logInfo("webhook.commit.task_refs", "Processed explicit commit task references", {
180→    sha: input.commit.sha,
181→    referencedTaskCount: referencedTaskIds.length,
182→    linkedTaskCount,
183→    unresolvedTaskCount: unresolvedTaskIds.length,
184→  });
185→
186→  const extractionSourceText = buildCommitExtractionSourceText(
187→    input.commit.message,
188→    linkedTaskSummaries,
189→    unresolvedTaskIds,
190→  );
191→
192→  // Load workspace graph context for extraction
193→  const graphContext = await loadWorkspaceGraphContext(
194→    input.surreal,
195→    input.workspaceRecord,
196→    60,
197→  );
198→
199→  // Run extraction on commit message
200→  const extractionOutput = await extractStructuredGraph({
201→    extractionModel: input.extractionModel,
202→    conversationHistory: [],
203→    graphContext,
204→    sourceText: extractionSourceText,
205→    onboarding: false,
206→    workspaceName: input.workspaceName,
207→    projectNames: input.projectNames,
208→  });
209→
210→  // Persist extracted entities and relationships
211→  const persisted = await persistExtractionOutput({
212→    surreal: input.surreal,
213→    extractionModel: input.extractionModel,
214→    embeddingModel: input.embeddingModel,
215→    embeddingDimension: input.embeddingDimension,
216→    extractionModelId: input.extractionModelId,
217→    extractionStoreThreshold: input.extractionStoreThreshold,
218→    workspaceRecord: input.workspaceRecord,
219→    sourceRecord: commitRecord as SourceRecord,
220→    sourceKind: "git_commit",
221→    sourceLabel: `commit ${input.commit.sha.slice(0, 8)}`,
222→    promptText: extractionSourceText,
223→    output: extractionOutput,
224→    sourceCommitRecord: commitRecord,
225→    now: input.now,
226→  });
227→
228→  // Auto-link decisions based on confidence
229→  const autoLinkedDecisions: string[] = [];
230→  const observationsCreated: string[] = [];
231→  const actions = classifyDecisionLinks(persisted.entities, input.autoLinkThreshold);
232→
233→  for (const action of actions) {
234→    const decisionRecord = new RecordId("decision", action.entityId);
235→
236→    if (action.action === "auto_link") {
237→      await input.surreal
238→        .relate(decisionRecord, new RecordId("implemented_by", randomUUID()), commitRecord, {
239→          commit_sha: input.commit.sha,
240→          linked_at: input.now,
241→        })
242→        .output("after");
243→
244→      autoLinkedDecisions.push(action.entityId);
245→      logInfo("webhook.commit.autolinked", "Auto-linked decision to commit", {
246→        decisionId: action.entityId,
247→        sha: input.commit.sha,
248→        confidence: action.confidence,
249→      });
250→    } else {
251→      const observation = await createObservation({
252→        surreal: input.surreal,
253→        workspaceRecord: input.workspaceRecord,
254→        text: `Commit ${input.commit.sha.slice(0, 8)} may implement decision "${action.text}" (confidence: ${(action.confidence * 100).toFixed(0)}%). Please confirm.`,
255→        severity: "info",
256→        sourceAgent: "git_webhook",
257→        now: input.now,
258→        relatedRecord: decisionRecord,
259→      });
260→
261→      observationsCreated.push(observation.id as string);
262→      logInfo("webhook.commit.observation", "Created confirmation observation", {
263→        decisionId: action.entityId,
264→        sha: input.commit.sha,
265→        confidence: action.confidence,
266→      });
267→    }
268→  }
269→
270→  return {
271→    commitRecord,
272→    entities: persisted.entities,
273→    relationships: persisted.relationships,
274→    autoLinkedDecisions,
275→    observationsCreated,
276→  };
277→}
278→
279→function buildCommitExtractionSourceText(
280→  message: string,
281→  linkedTasks: Array<{ id: string; title: string }>,
282→  unresolvedTaskIds: string[],
283→): string {
284→  if (linkedTasks.length === 0 && unresolvedTaskIds.length === 0) {
285→    return message;
286→  }
287→
288→  const lines = [message, "", "Explicit task references parsed from commit message:"];
289→  for (const task of linkedTasks) {
290→    lines.push(`- task:${task.id} (workspace task title: ${task.title})`);
291→  }
292→  for (const taskId of unresolvedTaskIds) {
293→    lines.push(`- task:${taskId} (not found in this workspace)`);
294→  }
295→  return lines.join("\n");
296→}
