 1→const SINGLE_TASK_REGEX = /\btask:([A-Za-z0-9_-]+)\b/gi;
 2→const TASK_LIST_REGEX = /\btasks:\s*([^\n\r;]+)/gi;
 3→const TASK_TOKEN_REGEX = /^[A-Za-z0-9_-]+$/;
 4→
 5→function isLikelyTaskId(value: string): boolean {
 6→  if (!TASK_TOKEN_REGEX.test(value)) return false;
 7→  if (value.length < 4) return false;
 8→  return /\d/.test(value);
 9→}
10→
11→export function extractReferencedTaskIds(message: string): string[] {
12→  const ids: string[] = [];
13→  const seen = new Set<string>();
14→
15→  const add = (raw: string): void => {
16→    const id = raw.trim();
17→    if (!isLikelyTaskId(id)) return;
18→    if (id.includes(":")) return;
19→    if (seen.has(id)) return;
20→    seen.add(id);
21→    ids.push(id);
22→  };
23→
24→  for (const match of message.matchAll(SINGLE_TASK_REGEX)) {
25→    add(match[1] as string);
26→  }
27→
28→  for (const match of message.matchAll(TASK_LIST_REGEX)) {
29→    const segment = (match[1] as string).trim();
30→    if (segment.length === 0) continue;
31→    for (const token of segment.split(/[,\s]+/)) {
32→      add(token);
33→    }
34→  }
35→
36→  return ids;
37→}
